+  spb::stop_bits::type get_stop_bits_asio() const
+  {
+    switch (m_stop_bits) {
+      case StopBits::ONE_POINT_FIVE:
+        return spb::stop_bits::onepointfive;
+        break;
+      case StopBits::TWO:
+        return spb::stop_bits::two;
+        break;
+      case StopBits::ONE:
+      default:
+        return spb::stop_bits::one;
